    def test_xss_email_0027(self, page: Page, xss_p: str):
        """XSS payload must not execute in email."""
        alerts: list = []
        page.on('dialog', lambda d: (alerts.append(d.message), d.dismiss()))
        page.goto(BASE_URL + '/contact-us', wait_until='commit', timeout=30000)
        page.wait_for_timeout(1200)
