    @pytest.mark.parametrize('xss_p', ['<script>alert(1)</script>', '"><script>alert(1)</script>', '<img src=x onerror=alert(1)>', '<svg onload=alert(1)>'])
    @pytest.mark.security
    def test_xss_search_0026(self, page: Page, xss_p: str):
        """XSS payload must not execute in search."""
        alerts: list = []
        page.on('dialog', lambda d: (alerts.append(d.message), d.dismiss()))
        page.goto(BASE_URL + '/tutor-login', wait_until='commit', timeout=30000)
        page.wait_for_timeout(1200)
        try:
            page.search.filter(visible=True).first.fill(xss_p, timeout=5000)
            page.wait_for_timeout(500)
            assert len(alerts) == 0, f'XSS executed! payload={xss_p!r} alerts={alerts}'
            assert '500' not in page.title(), f'Server error on XSS: {page.url}'
        except AssertionError: raise
        except Exception: pytest.skip(f'Field not found on {page.url}')

    @pytest.mark.parametrize('sqli_p', ["' OR '1'='1", "' OR '1'='1'--", "' OR 1=1--", "admin'--"])
    @pytest.mark.security
    def test_sqli_search_0027(self, page: Page, sqli_p: str):
        """SQLi must not expose DB errors in search."""
        db_errs = ['sql syntax', 'mysql_fetch', 'pg_query', 'sqlite_', 'ORA-', 'SQLSTATE', 'syntax error']
        page.goto(BASE_URL + '/tutor-login', wait_until='commit', timeout=30000)
        page.wait_for_timeout(1200)
        try:
            page.search.filter(visible=True).first.fill(sqli_p, timeout=5000)
            page.wait_for_timeout(500)
            content = page.content().lower()
            for kw in db_errs:
                assert kw not in content, f'DB error exposed! kw={kw!r} payload={sqli_p!r}'
        except AssertionError: raise
        except Exception: pytest.skip(f'Field not found on {page.url}')

